import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should quote a single basic sword with no modifiers");
    it.todo("should quote a single cursed item with 50% surcharge");
    it.todo("should quote a single highly enchanted item (level >= 5) with 30% surcharge");
    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% multi-contract discount after first contract");
    it.todo("should quote multiple items summing their base premiums");
    it.todo("should treat 3 alike components as a bundle with 60G base premium");
  });

  describe("claim", () => {
    it.todo("should apply 100G deductible and pay remainder");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to high-enchantment items (>= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
  });
});

