interface Customer {
  yearsWithMHPCO: number;
}

interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

const PROCESSING_FEE = 5;
const LOYALTY_YEARS_THRESHOLD = 2;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

export const quote = (customer: Customer, items: Item[], contractNumber: number): number => {
  const item = items[0];
  let basePremium: number;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) basePremium = 88;
  else if (contractNumber > 1) basePremium = 85;
  else if (item.cursed) basePremium = 165;
  else if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) basePremium = 143;
  else if (item.type === "amulet") basePremium = 66;
  else basePremium = 110;
  return basePremium + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

